    tiling.set_inN(inN);
    tiling.set_inC(inC);
    tiling.set_inD(inD);
    tiling.set_inH(inH);
    tiling.set_inW(inW);
    tiling.set_outD(outD);
    tiling.set_outH(outH);
    tiling.set_outW(outW);
    tiling.set_padLeft(padLeft);
    tiling.set_padRight(padRight);
    tiling.set_padTop(padTop);
